SELECT p.post_id AS postId, p.title AS title, p.answer_status AS answerStatus, p.category_code AS categoryCode, c.name AS categoryName, p.loginID AS loginID, u.name AS writerName, p.created_at AS createdAt, p.content AS content, p.fil_ori_name AS filOriName, p.fil_sav_name AS filSavName, p.extends AS extendsName, p.size AS size, p.logical_path AS logicalPath, p.physical_path AS physicalPath, p.is_deleted AS isDeleted, p.request_target AS requestTarget, CASE WHEN p.request_target IS NULL OR p.request_target = '' THEN '전체' WHEN u2.user_type = 'A' THEN u2.name WHEN u2.user_type = 'I' THEN CONCAT(u2.name, ' 강사') ELSE u2.name END AS requestTargetName FROM qna_post p JOIN qna_category c ON p.category_code = c.category_code JOIN tb_userinfo u ON p.loginID = u.loginID LEFT JOIN tb_userinfo u2 ON p.request_target = u2.loginID WHERE p.is_deleted = 'N'
AND ( p.request_target = #{loginID} OR p.request_target IS NULL OR p.request_target = '' )
AND p.answer_status = #{answerStatus}
AND p.category_code = #{category}
AND (p.title LIKE CONCAT('%', #{keyword}, '%') OR p.content LIKE CONCAT('%', #{keyword}, '%'))
ORDER BY p.created_at DESC LIMIT #{startNum}, #{pageSize}

SELECT COUNT(*)
FROM qna_post p
WHERE is_deleted = 'N'


